from database import db


def find_user(user_id):
    query = f"SELECT * FROM users WHERE id = {user_id}"
    return db.execute(query).fetchone()


def user_names(user_ids):
    names = []
    for user_id in user_ids:
        names.append(find_user(user_id)["name"])
    return names
